INSERT OR REPLACE INTO `audit_reports` (`id`, `ticker`, `year`, `report_type`, `auditor_name`, `audit_opinion`, `going_concern_issue`, `going_concern_detail`) VALUES
('VPB_2017_consolidated', 'VPB', 2017, 'consolidated', 'Ernst & Young Việt Nam', 'unqualified', 0, NULL),
('VPB_2018_parent', 'VPB', 2018, 'parent', 'Ernst & Young Việt Nam', 'unqualified', 0, NULL),
('VPB_2017_parent', 'VPB', 2017, 'parent', 'Công ty TNHH Ernst & Young Việt Nam', 'unqualified', 0, NULL),
('VPA_2025_consolidated', 'VPA', 2025, 'consolidated', 'Công ty TNHH Kiểm toán An Việt', 'unqualified', 1, 'Khoản lỗ lũy kế đến ngày 31/12/2025 là hơn 245 tỷ đồng (vượt quá vốn góp của chủ sở hữu hơn 94 tỷ đồng) và tại ngày 31/12/2025, số dư nợ ngắn hạn lớn hơn tài sản ngắn hạn 9 tỷ đồng. Công ty đã đạt được thỏa thuận với ngân hàng cho vay về việc giãn nợ gốc và lãi vay phải trả trong ngắn hạn nhưng vẫn gặp nhiều khó khăn về tài chính, cho thấy sự tồn tại của yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục của Công ty.'),
('VPA_2024_consolidated', 'VPA', 2024, 'consolidated', 'Công ty TNHH Kiểm toán An Việt', 'unqualified', 1, 'Khoản lỗ lũy kế đến ngày 31/12/2024 là hơn 200 tỷ đồng (vượt quá vốn góp của chủ sở hữu gần 61 tỷ đồng) và tại ngày 31/12/2024, số dư nợ ngắn hạn lớn hơn tài sản ngắn hạn xấp xỉ 22 tỷ đồng.'),
('VPA_2020_consolidated', 'VPA', 2020, 'consolidated', 'Công ty TNHH Kiểm toán và Thẩm định giá Việt Nam (AVA)', 'unqualified', 0, NULL),
('VPA_2022_consolidated', 'VPA', 2022, 'consolidated', 'Công ty TNHH Kiểm toán An Việt', 'unqualified', 1, 'Tính đến ngày 31/12/2022, Công ty có khoản lỗ lũy kế là 147.798.372.185 VND và số dư nợ ngắn hạn đã vượt tài sản ngắn hạn 19.152.331.904 VND, cho thấy sự tồn tại của yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục.'),
('VPA_2023_consolidated', 'VPA', 2023, 'consolidated', 'Công ty TNHH Kiểm toán An Việt', 'unqualified', 1, 'Lỗ lũy kế đến ngày 31/12/2023 là 161.587.109.469 VND, vượt quá vốn góp của chủ sở hữu 10.825.339.469 VND. Tuy nhiên, ý kiến kiểm toán viên không bị ảnh hưởng bởi vấn đề này.'),
('VPA_2019_consolidated', 'VPA', 2019, 'consolidated', 'Công ty TNHH Kiểm toán và Thẩm định giá Việt Nam (AVA)', 'unqualified', 0, NULL),
('VPA_2021_consolidated', 'VPA', 2021, 'consolidated', 'Công ty TNHH Kiểm toán và Thẩm định giá Việt Nam', 'unqualified', 0, NULL),
('VPA_2018_consolidated', 'VPA', 2018, 'consolidated', 'Công ty TNHH Kiểm toán và Thẩm định giá Việt Nam (AVA)', 'unqualified', 0, NULL),
('VPA_2016_consolidated', 'VPA', 2016, 'consolidated', 'Công ty TNHH Kiểm toán và Thẩm định giá Việt Nam (AVA)', 'unqualified', 0, NULL),
('VPA_2017_consolidated', 'VPA', 2017, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn tài chính Quốc tế (IFC)', 'unqualified', 0, NULL),
('VNZ_2025_consolidated', 'VNZ', 2025, 'consolidated', 'Ernst & Young Vietnam Limited', 'unqualified', 1, 'Tập đoàn phát sinh lỗ sau thuế 325.984.545.132 VND năm 2025 và tổng nợ ngắn hạn vượt tổng tài sản ngắn hạn 494.246.887.290 VND. Khả năng hoạt động liên tục phụ thuộc vào hoạt động kinh doanh có lợi nhuận trong tương lai và kế hoạch dòng tiền.'),
('VPA_2015_consolidated', 'VPA', 2015, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn Tài chính Quốc tế (IFC)', 'unqualified', 1, 'Tổng Nợ ngắn hạn tại ngày 31/12/2015 vượt quá tổng Tài sản ngắn hạn 27.189.717.621 đồng. Lỗ lũy kế là 18.761.670.713 đồng. Khoản nợ ngắn hạn lớn hơn tài sản ngắn hạn chủ yếu do khoản nợ phải trả của Công ty TNHH MTV Đóng tàu Hồng Hà tăng do quyết toán vốn đầu tư tàu VP1 và VP2.'),
('VNZ_2025_parent', 'VNZ', 2025, 'parent', 'Ernst & Young Việt Nam', 'unqualified', 1, 'Công ty phát sinh lỗ sau thuế 277,013,858,968 VNĐ năm 2025 và tổng nợ ngắn hạn vượt tài sản ngắn hạn 2,451,093,379,250 VNĐ. Khả năng hoạt động liên tục phụ thuộc vào kế hoạch kinh doanh có lợi nhuận và nguồn tài trợ bổ sung.'),
('VNZ_2023_consolidated', 'VNZ', 2023, 'consolidated', 'Ernst & Young Việt Nam', 'unqualified', 1, 'Tập đoàn phát sinh khoản lỗ thuần sau thuế với giá trị là 2.317.244.894.436 VND cho năm tài chính kết thúc ngày 31 tháng 12 năm 2023. Điều kiện này cho thấy có sự tồn tại của yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục của Tập đoàn. Tuy nhiên, Ban Tổng Giám đốc tin tưởng rằng, dựa trên kế hoạch dòng tiền dự phòng, Tập đoàn có thể đảm bảo đủ nguồn tiền để đáp ứng nhu cầu trong 12 tháng tới.'),
('VNZ_2024_consolidated', 'VNZ', 2024, 'consolidated', 'Ernst & Young Việt Nam', 'unqualified', 1, 'Công ty đã phát sinh khoản lỗ sau thuế thu nhập doanh nghiệp 1.808.101.943.534 VND cho năm tài chính kết thúc ngày 31/12/2024. Tổng nợ ngắn hạn vượt hơn tổng tài sản ngắn hạn 2.420.429.943.917 VND tại ngày 31/12/2024, cho thấy sự tồn tại của yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục.'),
('VNZ_2023_parent', 'VNZ', 2023, 'parent', 'Công ty TNHH Ernst & Young Việt Nam', 'unqualified', 1, 'Công ty phát sinh khoản lỗ thuần sau thuế với giá trị 341.341.410.151 VND cho năm tài chính kết thúc ngày 31/12/2023. Điều kiện này cho thấy có sự tồn tại của yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục của Công ty. Công ty đã lập kế hoạch cho 12 tháng tiếp theo để cải thiện dòng tiền từ hoạt động kinh doanh.'),
('VNY_2025_consolidated', 'VNY', 2025, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn UHY', 'unqualified', 0, NULL);
