('VNY_2022_consolidated', 'VNY', 2022, 'consolidated', 'UHY', 'unqualified', 0, NULL),
('VNY_2021_consolidated', 'VNY', 2021, 'consolidated', 'Công ty TNHH Kiểm toán CPA VIETNAM - Chi nhánh Miền Bắc', 'unqualified', 1, 'Tại thời điểm 31/12/2021, số lỗ lũy kế của đơn vị là 192.367.273.123 đồng vượt 49.867.583.123 đồng so với số vốn góp của chủ sở hữu. Nợ ngắn hạn vượt quá tài sản ngắn hạn là 21.828.885.834 đồng, chỉ ra yếu tố không chắc chắn trọng yếu ảnh hưởng đến khả năng hoạt động liên tục.'),
('VNY_2021_parent', 'VNY', 2021, 'parent', 'CPA VIETNAM – Chi nhánh Miền Bắc', 'unqualified', 1, 'Lỗ lũy kế vượt 49.867.583.123 đồng so với vốn góp và nợ phải trả ngắn hạn vượt tài sản ngắn hạn 3.363.896.215 đồng.'),
('VNY_2020_consolidated', 'VNY', 2020, 'consolidated', 'Công ty TNHH Kiểm toán CPA VIETNAM - Chi nhánh Miền Bắc', 'unqualified', 1, 'Tại thời điểm 31/12/2020, số lỗ lũy kế của đơn vị là 200.324.718.467 đồng vượt 113.986.572.988 đồng so với số vốn đầu tư của chủ sở hữu cùng thời điểm. Và cũng tại ngày đó, nợ ngắn hạn của đơn vị đã vượt quá tài sản ngắn hạn của đơn vị là 209.138.098.637 đồng. Các dấu hiệu trên chỉ ra yếu tố không chắc chắn trọng yếu ảnh hưởng đến khả năng hoạt động liên tục của đơn vị.'),
('VNY_2020_parent', 'VNY', 2020, 'parent', 'Công ty TNHH Kiểm toán CPA VIETNAM – Chi nhánh Miền Bắc', 'unqualified', 1, 'Tại thời điểm 31/12/2020, số lỗ lũy kế của đơn vị là 200.324.718.467 đồng vượt 117.241.479.529 đồng so với số vốn đầu tư của chủ sở hữu cùng thời điểm. Khoản nợ phải trả của đơn vị đã vượt quá tài sản ngắn hạn của đơn vị là 187.001.251.582 đồng. Các dấu hiệu trên chỉ ra yếu tố không chắc chắn trọng yếu ảnh hưởng đến khả năng hoạt động liên tục của đơn vị.'),
('VNY_2019_parent', 'VNY', 2019, 'parent', 'Công ty TNHH Kiểm toán CPA VIETNAM - Chi nhánh Miền Bắc', 'qualified', 1, 'Tại thời điểm 31/12/2019, số lỗ lũy kế của đơn vị là 202.078.403.727 đồng vượt 118.995.164.789 đồng so với số vốn đầu tư của chủ sở hữu cùng thời điểm. Và cũng tại ngày đó, khoản nợ phải trả của đơn vị đã vượt quá tài sản ngắn hạn của đơn vị là 199.675.304.969 đồng. Các dấu hiệu trên chỉ ra yếu tố không chắc chắn trọng yếu ảnh hưởng đến khả năng hoạt động liên tục của đơn vị.'),
('VNY_2018_consolidated', 'VNY', 2018, 'consolidated', 'Công ty TNHH Kiểm toán CPA VIETNAM', 'qualified', 1, 'Lỗ lũy kế 182.273.994.532 đồng vượt 95.935.849.053 đồng so với vốn đầu tư của chủ sở hữu; nợ phải trả vượt tài sản ngắn hạn 211.334.345.509 đồng.'),
('VNY_2017_consolidated', 'VNY', 2017, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn UHY', 'qualified', 1, 'Khoản lỗ sau thuế chưa phân phối lũy kế đến 31/12/2017 là 166.273.730.338 đồng đã vượt Vốn chủ sở hữu (79.863.035.706 đồng). Công ty đang mất khả năng thanh toán các khoản nợ ngắn hạn, cho thấy sự tồn tại của yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về hoạt động liên tục.'),
('VNY_2017_parent', 'VNY', 2017, 'parent', 'Công ty TNHH Kiểm toán và Tư vấn UHY', 'qualified', 1, 'Khoản lỗ sau thuế chưa phân phối lũy kế của Công ty đến ngày 31/12/2017 là 166.273.730.338 đồng đã vượt Vốn chủ sở hữu số tiền 83.117.942.247 đồng, và theo đánh giá của Ban lãnh đạo Công ty tại thuyết minh số 13 Công ty đang mất khả năng thanh toán các khoản nợ ngắn hạn, điều kiện này cho thấy sự tồn tại của yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về hoạt động liên tục của Công ty.'),
('VNY_2019_consolidated', 'VNY', 2019, 'consolidated', 'Công ty TNHH Kiểm toán CPA VIETNAM - Chi nhánh Miền Bắc', 'qualified', 1, 'Tại thời điểm 31/12/2019, số lỗ lũy kế của đơn vị là 199.086.965.040 đồng vượt 112.748.819.561 đồng so với số vốn đầu tư của chủ sở hữu cùng thời điểm. Nợ ngắn hạn vượt quá tài sản ngắn hạn là 69.699.571.078 đồng. Kiểm toán viên không đủ cơ sở để xác định 03 khoản vay cá nhân với tổng số tiền 19.991.125.000 đồng và lãi phải trả 2.005.858.000 đồng do không có hợp đồng vay giữa Công ty và các cá nhân.'),
('VNX_2021_consolidated', 'VNX', 2021, 'consolidated', 'Công ty TNHH Kiểm toán và Thẩm định giá Việt Nam (AVA)', 'unqualified', 0, NULL),
