INSERT OR REPLACE INTO `audit_reports` (`id`, `ticker`, `year`, `report_type`, `auditor_name`, `audit_opinion`, `going_concern_issue`, `going_concern_detail`) VALUES
('VNP_2024_consolidated', 'VNP', 2024, 'consolidated', 'Công ty TNHH Kiểm Toán VACO', 'unqualified', 0, NULL),
('VNP_2023_parent', 'VNP', 2023, 'parent', 'Công ty TNHH Kiểm toán VACO', 'unqualified', 0, NULL),
('VNP_2023_consolidated', 'VNP', 2023, 'consolidated', 'CÔNG TY TNHH KIỂM TOÁN VACO', 'unqualified', 0, NULL),
('VNP_2022_consolidated', 'VNP', 2022, 'consolidated', 'Công ty TNHH Kiểm toán VACO', 'unqualified', 0, NULL),
('VNP_2021_consolidated', 'VNP', 2021, 'consolidated', 'A&C Auditing and Consulting Co., Ltd.', 'unqualified', 0, NULL),
('VNP_2019_parent', 'VNP', 2019, 'parent', 'AISC', 'qualified', 0, NULL),
('VNP_2020_consolidated', 'VNP', 2020, 'consolidated', 'Công ty TNHH Kiểm toán và Dịch vụ Tin học TP.HCM (AISC)', 'unqualified', 1, 'Đến thời điểm 31 tháng 12 năm 2020, nợ ngắn hạn đã vượt quá tài sản ngắn hạn với số tiền 17.782.201.367 VND và Công ty phát sinh lỗ lũy kế đến ngày 31 tháng 12 năm 2020 là 56.103.958.534 VND. Điều này gây nên quan ngại về khả năng tạo tiền của Công ty để thanh toán cho các khoản nợ đến hạn thanh toán.'),
('VNP_2019_consolidated', 'VNP', 2019, 'consolidated', 'Công ty TNHH Kiểm toán và Dịch vụ Tin học TP.HCM', 'qualified', 0, NULL),
('VNP_2018_consolidated', 'VNP', 2018, 'consolidated', 'Công ty TNHH Kiểm toán và Dịch vụ Tin học TP.HCM (AISC)', 'qualified', 0, NULL),
('VNP_2018_parent', 'VNP', 2018, 'parent', 'Công ty TNHH Kiểm toán và Dịch vụ Tin học TP.HCM (AISC)', 'qualified', 0, NULL),
('VNP_2017_consolidated', 'VNP', 2017, 'consolidated', 'Công ty TNHH Kiểm toán VACO', 'qualified', 0, NULL),
('VNP_2017_parent', 'VNP', 2017, 'parent', 'Công ty TNHH Kiểm toán VACO', 'qualified', 1, 'Tại ngày báo cáo, nợ ngắn hạn đã vượt quá tài sản ngắn hạn với giá trị 55.841.710.985 đồng, lỗ lũy kế là 100.066.867.405 đồng (chiếm 52% vốn điều lệ thực tế đã góp). Điều này cho thấy dấu hiệu về khả năng thanh toán của Công ty có thể ảnh hưởng đến khả năng hoạt động liên tục. Ban lãnh đạo nhận định hoạt động và kết quả kinh doanh trong các năm tới sẽ tăng trưởng tốt hơn để bù đắp các khoản lỗ này và thanh toán các khoản nợ quá hạn, do đó Công ty vẫn tiếp tục hoạt động trong thời gian ít nhất 12 tháng tới.'),
('VNP_2016_consolidated', 'VNP', 2016, 'consolidated', 'Công ty TNHH Kiểm toán VACO', 'qualified', 0, NULL),
('VNP_2016_parent', 'VNP', 2016, 'parent', 'Công ty TNHH Kiểm toán VACO', 'qualified', 0, NULL),
